changeSet.sql:
ALTER TABLE public.skills        ADD COLUMN IF NOT EXISTS created_by uuid, ADD COLUMN IF NOT EXISTS updated_by uuid;
ALTER TABLE public.feat          ADD COLUMN IF NOT EXISTS created_by uuid, ADD COLUMN IF NOT EXISTS updated_by uuid;
ALTER TABLE public.item_types    ADD COLUMN IF NOT EXISTS created_by uuid, ADD COLUMN IF NOT EXISTS updated_by uuid;
ALTER TABLE public.buffs_debuffs ADD COLUMN IF NOT EXISTS created_by uuid, ADD COLUMN IF NOT EXISTS updated_by uuid;

ALTER TABLE public.skills        ADD CONSTRAINT fk_skills_created_by        FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.skills        ADD CONSTRAINT fk_skills_updated_by        FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.feat          ADD CONSTRAINT fk_feat_created_by          FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.feat          ADD CONSTRAINT fk_feat_updated_by          FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.item_types    ADD CONSTRAINT fk_item_types_created_by    FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.item_types    ADD CONSTRAINT fk_item_types_updated_by    FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.buffs_debuffs ADD CONSTRAINT fk_buffs_debuffs_created_by FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
ALTER TABLE public.buffs_debuffs ADD CONSTRAINT fk_buffs_debuffs_updated_by FOREIGN KEY (updated_by) REFERENCES public.users(id) ON DELETE SET NULL;

UPDATE public.skills s        SET created_by = hp.author_id, updated_by = hp.author_id FROM public.homebrew_packages hp WHERE s.homebrew_id  = hp.id AND s.created_by  IS NULL;
UPDATE public.feat f          SET created_by = hp.author_id, updated_by = hp.author_id FROM public.homebrew_packages hp WHERE f.homebrew_id  = hp.id AND f.created_by  IS NULL;
UPDATE public.item_types it   SET created_by = hp.author_id, updated_by = hp.author_id FROM public.homebrew_packages hp WHERE it.homebrew_id = hp.id AND it.created_by IS NULL;
UPDATE public.buffs_debuffs b SET created_by = hp.author_id, updated_by = hp.author_id FROM public.homebrew_packages hp WHERE b.homebrew_id  = hp.id AND b.created_by  IS NULL;

rollback.sql:
ALTER TABLE public.skills        DROP CONSTRAINT IF EXISTS fk_skills_created_by,        DROP CONSTRAINT IF EXISTS fk_skills_updated_by;
ALTER TABLE public.feat          DROP CONSTRAINT IF EXISTS fk_feat_created_by,          DROP CONSTRAINT IF EXISTS fk_feat_updated_by;
ALTER TABLE public.item_types    DROP CONSTRAINT IF EXISTS fk_item_types_created_by,    DROP CONSTRAINT IF EXISTS fk_item_types_updated_by;
ALTER TABLE public.buffs_debuffs DROP CONSTRAINT IF EXISTS fk_buffs_debuffs_created_by, DROP CONSTRAINT IF EXISTS fk_buffs_debuffs_updated_by;
ALTER TABLE public.skills        DROP COLUMN IF EXISTS created_by, DROP COLUMN IF EXISTS updated_by;
ALTER TABLE public.feat          DROP COLUMN IF EXISTS created_by, DROP COLUMN IF EXISTS updated_by;
ALTER TABLE public.item_types    DROP COLUMN IF EXISTS created_by, DROP COLUMN IF EXISTS updated_by;
ALTER TABLE public.buffs_debuffs DROP COLUMN IF EXISTS created_by, DROP COLUMN IF EXISTS updated_by;
